const LARGE_STACK: usize = 16 * 1024 * 1024;

fn tmp_path(name: &str) -> PathBuf {
    std::env::temp_dir().join(name)
}

fn cleanup(path: &std::path::Path) {
    let _ = std::fs::remove_file(path);
}

fn run_on_large_stack<F, T>(f: F) -> T
where
    F: FnOnce() -> T + Send + 'static,
    T: Send + 'static,
{
    std::thread::Builder::new()
        .stack_size(LARGE_STACK)
        .spawn(f)
        .unwrap()
        .join()
        .unwrap()
}

// Deterministic LCG — avoids pulling in rand crate.
fn lcg_next(state: &mut u64) -> u64 {
    *state = state.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
    *state
}

// Populate a fresh store with n nodes and close it. Pre-population is outside
// all timing windows — this is setup cost only.
fn populate(path: &std::path::Path, n: u64) {
    cleanup(path);
    let path = path.to_path_buf();
    run_on_large_stack(move || {
        let mut gs = GraphStore::create(&path).unwrap();
        for _ in 0..n {
            gs.insert_node("Person").unwrap();
        }
        gs.close().unwrap();
    });
}

// Sizes to benchmark, capped by NEXORA_BENCH_MAX (default: 1_000_000).
// Example: NEXORA_BENCH_MAX=10000 cargo bench --bench graph_bench
fn bench_sizes() -> Vec<u64> {
    let max = std::env::var("NEXORA_BENCH_MAX")
        .ok()
        .and_then(|s| s.parse().ok())
        .unwrap_or(1_000_000u64);

    [1_000u64, 10_000, 100_000, 1_000_000]
        .iter()
        .copied()
        .filter(|&n| n <= max)
        .collect()
}

// Reduce sample count for benchmarks where one iteration is inherently slow
// (large scans, large bulk inserts) so the total run stays reasonable.
fn sample_size_for(n: u64) -> usize {
    match n {
        n if n >= 1_000_000 => 10,
        n if n >= 100_000  => 20,
        n if n >= 10_000   => 50,
        _                  => 100,
    }
}

